1	import { Link, useNavigate } from "react-router-dom";
2	import {
3	  Sheet,
4	  SheetContent,
5	  SheetHeader,
6	  SheetTitle,
7	} from "@/components/ui/sheet";
8	import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
9	import { Button } from "@/components/ui/button";
10	import { Badge } from "@/components/ui/badge";
11	import { supabase } from "@/integrations/supabase/client";
12	import {
13	  CreditCard,
14	  Bell,
15	  Settings,
16	  LogOut,
17	  Crown,
18	  Sparkles,
19	} from "lucide-react";
20	import { Separator } from "@/components/ui/separator";
21	import { useLanguage } from "@/i18n/LanguageContext";
22	import { useSubscription } from "@/hooks/use-subscription";
23	import { VerifiedBadge } from "@/components/ui/VerifiedBadge";
24	
25	interface ProfileDrawerProps {
26	  isOpen: boolean;
27	  onClose: () => void;
28	  profile: any;
29	  userType: "creator" | "brand";
30	}
31	
32	const ProfileDrawer = ({ isOpen, onClose, profile, userType }: ProfileDrawerProps) => {
33	  const navigate = useNavigate();
34	  const { t } = useLanguage();
35	  const subscription = useSubscription();
36	
37	  const handleSignOut = async () => {
38	    await supabase.auth.signOut();
39	    navigate("/");
40	  };
41	
42	  const menuItems = [
43	    { icon: CreditCard, label: t("profile.paymentsBilling"), path: "/profile/payments-billing" },
44	    { icon: Bell, label: t("profile.notifications"), path: "/profile/notifications" },
45	    { icon: Settings, label: t("profile.settings"), path: "/profile/settings" },
46	  ];
47	
48	  return (
49	    <Sheet open={isOpen} onOpenChange={onClose}>
50	      <SheetContent side="right" className="bg-black border-white/10 w-full sm:w-[320px]">
51	        <SheetHeader className="pb-6">
52	          <SheetTitle className="text-white font-vollkorn">{t("profile.menu")}</SheetTitle>
53	        </SheetHeader>
54	
55	        <div className="flex items-center gap-3 p-4 rounded-xl bg-white/5 mb-6">
56	          <Avatar className="h-12 w-12">
57	            <AvatarImage src={profile?.avatar_url} />
58	            <AvatarFallback className="bg-bronze text-white">
59	              {profile?.display_name?.charAt(0) || profile?.email?.charAt(0) || "U"}
60	            </AvatarFallback>
61	          </Avatar>
62	          <div className="flex-1 min-w-0">
63	            <div className="flex items-center gap-1.5">
64	              <p className="font-poppins text-sm font-semibold text-white truncate">
65	                {profile?.display_name || "User"}
66	              </p>
67	              {subscription.limits.hasVerifiedBadge && (
68	                <VerifiedBadge size="sm" />
69	              )}
70	            </div>
71	            <p className="text-xs text-white/50 truncate">{profile?.email}</p>
72	            <Badge
73	              variant="outline"
74	              className={
75	                userType === "creator"
76	                  ? "mt-1.5 text-[10px] font-semibold border-bronze text-bronze bg-bronze/15 px-2 py-0.5"
77	                  : "mt-1.5 text-[10px] font-semibold border-blue-400 text-blue-400 bg-blue-400/15 px-2 py-0.5"
78	              }
79	            >
80	              {userType === "creator" ? "Creator" : "Brand"}
81	              {!subscription.isFree && " · Pro"}
82	            </Badge>
83	          </div>
84	        </div>
85	
86	        {/* Upgrade / Manage subscription */}
87	        {subscription.isFree ? (
88	          <Link
89	            to="/pricing"
90	            onClick={onClose}
91	            className="flex items-center gap-3 px-4 py-3 mb-2 rounded-lg bg-gradient-to-r from-bronze to-bronze-dark text-white hover:opacity-90 transition-all"
92	          >
93	            <Crown className="h-5 w-5" />
94	            <span className="font-poppins text-sm font-semibold">Upgrade to Pro</span>
95	          </Link>
96	        ) : (
97	          <Link
98	            to="/profile/payments-billing"
99	            onClick={onClose}
100	            className="flex items-center gap-3 px-4 py-3 mb-2 rounded-lg bg-blue-500/10 border border-blue-500/20 text-blue-400 hover:bg-blue-500/20 transition-all"
101	          >
102	            <Sparkles className="h-5 w-5" />
103	            <span className="font-poppins text-sm font-semibold">Manage Subscription</span>
104	          </Link>
105	        )}
106	
107	        <Separator className="bg-white/10 mb-4" />
108	
109	        <nav className="space-y-1">
110	          {menuItems.map((item) => {
111	            const Icon = item.icon;
112	            return (
113	              <Link
114	                key={item.path}
115	                to={item.path}
116	                onClick={onClose}
117	                className="flex items-center gap-3 px-4 py-3 rounded-lg text-white/80 hover:text-bronze hover:bg-white/5 transition-all"
118	              >
119	                <Icon className="h-5 w-5" />
120	                <span className="font-poppins text-sm font-medium">{item.label}</span>
121	              </Link>
122	            );
123	          })}
124	        </nav>
125	
126	        <Separator className="bg-white/10 my-4" />
127	
128	        <Button
129	          variant="ghost"
130	          onClick={handleSignOut}
131	          className="w-full justify-start gap-3 text-white/80 hover:text-red-400 hover:bg-white/5"
132	        >
133	          <LogOut className="h-5 w-5" />
134	          <span className="font-poppins text-sm font-medium">{t("profile.logout")}</span>
135	        </Button>
136	      </SheetContent>
137	    </Sheet>
138	  );
139	};
140	
141	export default ProfileDrawer;
