1	import { Link, useLocation, useNavigate } from "react-router-dom";
2	import { Home, Sparkles, MoreHorizontal, Briefcase, Crown } from "lucide-react";
3	import { cn } from "@/lib/utils";
4	import {
5	  Sheet,
6	  SheetContent,
7	  SheetHeader,
8	  SheetTitle,
9	  SheetTrigger,
10	} from "@/components/ui/sheet";
11	import { Button } from "@/components/ui/button";
12	import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
13	import { Separator } from "@/components/ui/separator";
14	import { ScrollArea } from "@/components/ui/scroll-area";
15	import { supabase } from "@/integrations/supabase/client";
16	import { useState, useEffect } from "react";
17	import { useLanguage } from "@/i18n/LanguageContext";
18	
19	const MobileBottomNav = () => {
20	  const location = useLocation();
21	  const navigate = useNavigate();
22	  const { t } = useLanguage();
23	  const [profile, setProfile] = useState<any>(null);
24	  const [userType, setUserType] = useState<"creator" | "brand" | null>(null);
25	  const [sheetOpen, setSheetOpen] = useState(false);
26	
27	  useEffect(() => {
28	    const fetchProfile = async () => {
29	      const { data: { session } } = await supabase.auth.getSession();
30	      if (session) {
31	        const { data: profileData } = await supabase
32	          .from("profiles")
33	          .select("*")
34	          .eq("id", session.user.id)
35	          .single();
36	        setProfile(profileData);
37	        setUserType(profileData?.user_type || null);
38	      }
39	    };
40	    fetchProfile();
41	  }, []);
42	
43	  const isActive = (path: string) => {
44	    return location.pathname === path || location.pathname.startsWith(path + "/");
45	  };
46	
47	  const handleSignOut = async () => {
48	    await supabase.auth.signOut();
49	    navigate("/");
50	    setSheetOpen(false);
51	  };
52	
53	  const handleNavigation = (path: string) => {
54	    navigate(path);
55	    setSheetOpen(false);
56	  };
57	
58	  const navItems = [
59	    { id: "kira", label: "Kira", icon: Sparkles, path: "/kira" },
60	    { id: "studio", label: "Studio", icon: Briefcase, path: "/crevia-studio" },
61	  ];
62	
63	  return (
64	    <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 bg-black border-t border-white/10 safe-area-pb">
65	      <div className="grid grid-cols-3 h-16">
66	        {navItems.map((item) => {
67	          const Icon = item.icon;
68	          const active = isActive(item.path);
69	
70	          return (
71	            <Link
72	              key={item.id}
73	              to={item.path}
74	              className={cn(
75	                "flex flex-col items-center justify-center gap-1 transition-all duration-[400ms] ease-[cubic-bezier(0.32,0.72,0,1)] group",
76	                active ? "text-bronze" : "text-white/60"
77	              )}
78	            >
79	              <Icon className={cn(
80	                "h-5 w-5 transition-all duration-[400ms] ease-[cubic-bezier(0.32,0.72,0,1)] group-hover:scale-110", 
81	                active && "drop-shadow-[0_0_8px_rgba(207,129,80,0.5)]"
82	              )} />
83	              <span className="font-poppins text-xs font-medium">{item.label}</span>
84	            </Link>
85	          );
86	        })}
87	
88	        <Sheet open={sheetOpen} onOpenChange={setSheetOpen}>
89	          <SheetTrigger asChild>
90	            <button className="flex flex-col items-center justify-center gap-1 text-white/60">
91	              <MoreHorizontal className="h-5 w-5" />
92	              <span className="font-poppins text-xs font-medium">{t("common.more")}</span>
93	            </button>
94	          </SheetTrigger>
95	          <SheetContent side="bottom" className="bg-black border-white/10 h-[85vh] max-h-[85vh] flex flex-col p-0">
96	            <SheetHeader className="px-4 pt-4 pb-2 flex-shrink-0">
97	              <SheetTitle className="text-white font-vollkorn text-lg">{t("nav.moreOptions")}</SheetTitle>
98	            </SheetHeader>
99	            
100	            <ScrollArea className="flex-1 px-4">
101	              {profile && (
102	                <div className="flex items-center gap-3 p-3 sm:p-4 rounded-2xl bg-gradient-to-br from-white/10 to-white/5 border border-white/10 mb-4">
103	                  <Avatar className="h-11 w-11 sm:h-12 sm:w-12 ring-2 ring-bronze/30 flex-shrink-0">
104	                    <AvatarImage src={profile?.avatar_url} />
105	                    <AvatarFallback className="bg-gradient-to-br from-bronze to-bronze-dark text-white font-semibold text-sm">
106	                      {profile?.display_name?.charAt(0) || profile?.email?.charAt(0) || "U"}
107	                    </AvatarFallback>
108	                  </Avatar>
109	                  <div className="flex-1 min-w-0">
110	                    <p className="font-poppins text-sm font-semibold text-white truncate">
111	                      {profile?.display_name || "User"}
112	                    </p>
113	                    <p className="text-xs text-white/50 truncate">{profile?.email}</p>
114	                    {userType && (
115	                      <span className="inline-flex items-center mt-1 px-2 py-0.5 rounded-full text-[10px] font-medium bg-bronze/20 text-bronze border border-bronze/30 capitalize">
116	                        {userType}
117	                      </span>
118	                    )}
119	                  </div>
120	                </div>
121	              )}
122	              
123	              <div className="space-y-4 pb-8">
124	
125	                {/* Upgrade to Pro — always visible */}
126	                <Link
127	                  to="/pricing"
128	                  onClick={() => setSheetOpen(false)}
129	                  className="flex items-center gap-3 px-4 py-3.5 rounded-xl bg-gradient-to-r from-bronze to-bronze-dark text-white hover:opacity-90 transition-all w-full"
130	                >
131	                  <Crown className="h-5 w-5 flex-shrink-0" />
132	                  <span className="font-poppins text-sm font-semibold">Upgrade to Pro</span>
133	                </Link>
134	
135	                <Separator className="bg-white/10" />
136	
137	                <div className="space-y-1">
138	                  <p className="text-[10px] font-medium text-white/40 uppercase tracking-wider px-2 mb-1">{t("nav.account")}</p>
139	                  <Button 
140	                    variant="ghost" 
141	                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
142	                    onClick={() => handleNavigation("/profile/settings")}
143	                  >
144	                    {t("profile.settings")}
145	                  </Button>
146	                  <Button 
147	                    variant="ghost" 
148	                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
149	                    onClick={() => handleNavigation("/profile/payments-billing")}
150	                  >
151	                    {t("profile.paymentsBilling")}
152	                  </Button>
153	                  <Button 
154	                    variant="ghost" 
155	                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
156	                    onClick={() => handleNavigation("/profile/feedback")}
157	                  >
158	                    {t("nav.feedback")}
159	                  </Button>
160	                </div>
161	
162	                <Separator className="bg-white/10" />
163	
164	                <div className="space-y-1">
165	                  <p className="text-[10px] font-medium text-white/40 uppercase tracking-wider px-2 mb-1">{t("nav.support")}</p>
166	                  <Button 
167	                    variant="ghost" 
168	                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
169	                    onClick={() => handleNavigation("/profile/help")}
170	                  >
171	                    {t("nav.helpSupport")}
172	                  </Button>
173	                  <Button 
174	                    variant="ghost" 
175	                    className="w-full justify-start text-white/90 hover:text-bronze hover:bg-white/5 h-11 text-sm font-medium rounded-xl"
176	                    onClick={() => handleNavigation("/app/about")}
177	                  >
178	                    {t("nav.aboutCrevia")}
179	                  </Button>
180	                </div>
181	
182	                <Separator className="bg-white/10" />
183	
184	                <div className="space-y-1">
185	                  <p className="text-[10px] font-medium text-white/40 uppercase tracking-wider px-2 mb-1">{t("nav.legal")}</p>
186	                  <div className="flex gap-2">
187	                    <Button 
188	                      variant="ghost" 
189	                      className="flex-1 text-white/60 hover:text-bronze hover:bg-white/5 h-11 text-xs font-medium rounded-xl"
190	                      onClick={() => handleNavigation("/privacy-policy")}
191	                    >
192	                      {t("nav.privacy")}
193	                    </Button>
194	                    <Button 
195	                      variant="ghost" 
196	                      className="flex-1 text-white/60 hover:text-bronze hover:bg-white/5 h-11 text-xs font-medium rounded-xl"
197	                      onClick={() => handleNavigation("/terms-of-service")}
198	                    >
199	                      {t("nav.terms")}
200	                    </Button>
201	                  </div>
202	                </div>
203	
204	                <Separator className="bg-white/10" />
205	
206	                <Button 
207	                  variant="ghost" 
208	                  className="w-full justify-start text-red-400 hover:text-red-300 hover:bg-red-500/10 h-11 text-sm font-medium rounded-xl"
209	                  onClick={handleSignOut}
210	                >
211	                  {t("nav.logOut")}
212	                </Button>
213	              </div>
214	            </ScrollArea>
215	          </SheetContent>
216	        </Sheet>
217	      </div>
218	    </nav>
219	  );
220	};
221	
222	export default MobileBottomNav;
